export class AppCustomizationImpl {
    static readonly components = [];

    static readonly providers = [
        CustomActionService,
        {
            provide: CUSTOM_FEATURE_ACTIONS,
            useValue: [
                {
                    name: 'custom-action',
                    action: CustomActionService,
                },
            ],
            multi: true,
        },
    ];

    static readonly imports = [
        BucCommonComponentsModule,
        BucFeatureComponentsModule,
    ];
}

@Injectable()
export class CustomActionService {
    constructor(
        private actionProcessorService: ActionProcessorService,
        private ccNavigationSvc: CallCenterNavigationService
    ) {
        this.actionProcessorService.select<any>('custom-action').subscribe(({params}) => {
            this.openCustomModal(params);
        });
    }

    private openCustomModal(params: any) {
        const orderDetailsData = params.data;
        const orderHeaderKey = orderDetailsData.pageObject.OrderHeaderKey;
        const orderNo = orderDetailsData.pageObject.OrderNo;
        const enterpriseCode = orderDetailsData.pageObject.EnterpriseCode;

        if (!orderDetailsData) return;

        const opened = this.ccNavigationSvc.openUrlInNewTab('/custom-modal', {
            originalOrderNo: orderNo,
            originalOrderHeaderKey: orderHeaderKey,
            enterpriseCode: enterpriseCode
        });

        console.log('openUrlInNewTab returned:', opened);
    }
}
